set-variable.value:
@{
                try {
                    var body = context.Response.Body.As<JObject>(preserveContent: true);
                    var choices = body["choices"] as JArray;
                    if (choices == null || choices.Count == 0) return string.Empty;
                    var sb = new System.Text.StringBuilder();
                    foreach (var c in choices) {
                        var msg = c["message"];
                        string txt = null;
                        if (msg != null) txt = (string)msg["content"];
                        if (txt == null) txt = (string)c["text"];
                        if (!string.IsNullOrEmpty(txt)) {
                            if (sb.Length > 0) sb.Append("\n");
                            sb.Append(txt);
                        }
                    }
                    return sb.ToString();
                } catch { return string.Empty; }
            }

send-request.set-body:
@{
                            return new JObject(
                                new JProperty("text", (string)context.Variables["assistantText"]),
                                new JProperty("language", "en")
                            ).ToString();
                        }

when.condition:
@{
                            var r = (IResponse)context.Variables["redactResponse"];
                            return r != null && r.StatusCode == 200;
                        }

set-variable.value:
@{
                                try {
                                    var r = (IResponse)context.Variables["redactResponse"];
                                    var rb = r.Body.As<JObject>(preserveContent: true);
                                    return (string)rb["text"] ?? string.Empty;
                                } catch { return string.Empty; }
                            }

when.set-body:
@{
                                try {
                                    var body = context.Response.Body.As<JObject>(preserveContent: true);
                                    var choices = body["choices"] as JArray;
                                    var redacted = (string)context.Variables["redactedText"];
                                    if (choices != null && choices.Count > 0 && !string.IsNullOrEmpty(redacted)) {
                                        // For multi-choice responses we put the
                                        // full redacted blob into choice[0] and
                                        // blank the rest, since we lost per-choice
                                        // boundaries when we concatenated. The
                                        // workshop policy uses n=1 so this is the
                                        // common case anyway.
                                        var first = choices[0];
                                        var msg = first["message"];
                                        if (msg != null) msg["content"] = redacted;
                                        else first["text"] = redacted;
                                        for (int i = 1; i < choices.Count; i++) {
                                            var ci = choices[i];
                                            var mi = ci["message"];
                                            if (mi != null) mi["content"] = string.Empty;
                                            else ci["text"] = string.Empty;
                                        }
                                    }
                                    return body.ToString();
                                } catch {
                                    // Re-emit the original body on any JSON edit failure.
                                    return context.Response.Body.As<string>(preserveContent: true);
                                }
                            }
